        ? Number(formData.usageLimit)
        : undefined,
      usagePerUser: formData.usagePerUser
        ? Number(formData.usagePerUser)
        : undefined,
    };

    if (isEditing && coupon) {
      updateCoupon.mutate(
        { id: coupon.id, data: payload },
        { onSuccess: onClose }
      );
    } else {
      createCoupon.mutate(
        { ...payload, code: formData.code.trim().toUpperCase() },
        { onSuccess: onClose }
      );
    }
  }

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="sm:max-w-[560px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{isEditing ? "Edit Coupon" : "Create Coupon"}</DialogTitle>
          <DialogDescription>
            {isEditing
              ? "Update the coupon details below."
              : "Create a new discount coupon."}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit}>
          <div className="grid gap-4 py-4">
            {/* Code — only on create */}
            {!isEditing && (
              <div className="space-y-1.5">
                <Label htmlFor="code">Code *</Label>
                <Input
                  id="code"
                  placeholder="SUMMER20"
                  disabled={isPending}
                  className={errors.code ? "border-destructive" : ""}
                  {...field("code")}
                  onChange={(e) => {
                    setFormData((prev) => ({
                      ...prev,
                      code: e.target.value.toUpperCase(),
                    }));
                    if (errors.code)
                      setErrors((prev) => ({ ...prev, code: undefined }));
                  }}
                />
                {errors.code && (
                  <p className="text-sm text-destructive">{errors.code}</p>
                )}
              </div>
            )}

            {/* Description */}
            <div className="space-y-1.5">
              <Label htmlFor="description">Description *</Label>
              <Textarea
                id="description"
                placeholder="Short description of this coupon"
                rows={2}
                disabled={isPending}
                className={errors.description ? "border-destructive" : ""}
                {...field("description")}
              />
              {errors.description && (
                <p className="text-sm text-destructive">{errors.description}</p>
              )}
            </div>

            {/* Discount Type + Value */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label>Discount Type *</Label>
                <Select
                  value={formData.discountType}
                  onValueChange={(v) =>
                    setFormData((prev) => ({ ...prev, discountType: v }))
                  }
                  disabled={isPending}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Percentage">Percentage (%)</SelectItem>
                    <SelectItem value="FixedAmount">Fixed Amount ($)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="discountValue">
                  Value {formData.discountType === "Percentage" ? "(%)" : "($)"} *
                </Label>
                <Input
                  id="discountValue"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder={
                    formData.discountType === "Percentage" ? "20" : "10.00"
                  }
                  disabled={isPending}
                  className={errors.discountValue ? "border-destructive" : ""}
                  {...field("discountValue")}
                />
                {errors.discountValue && (
                  <p className="text-sm text-destructive">
                    {errors.discountValue}
                  </p>
                )}
              </div>
            </div>

            {/* Valid From + Valid Until */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="validFrom">Valid From *</Label>
                <Input
                  id="validFrom"
                  type="date"
                  disabled={isPending}
                  className={errors.validFrom ? "border-destructive" : ""}
                  {...field("validFrom")}
                />
                {errors.validFrom && (
                  <p className="text-sm text-destructive">{errors.validFrom}</p>
                )}
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="validUntil">Valid Until</Label>
                <Input
                  id="validUntil"
                  type="date"
                  disabled={isPending}
                  {...field("validUntil")}
                />
              </div>
            </div>

            {/* Optional constraints */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="minOrderAmount">Min Order Amount ($)</Label>
                <Input
                  id="minOrderAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="50.00"
                  disabled={isPending}
                  {...field("minOrderAmount")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="maxDiscountAmount">Max Discount ($)</Label>
                <Input
                  id="maxDiscountAmount"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="100.00"
                  disabled={isPending}
                  {...field("maxDiscountAmount")}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label htmlFor="usageLimit">Total Usage Limit</Label>
                <Input
                  id="usageLimit"
                  type="number"
                  min="1"
                  placeholder="100"
                  disabled={isPending}
                  {...field("usageLimit")}
                />
              </div>
              <div className="space-y-1.5">
                <Label htmlFor="usagePerUser">Per-User Limit</Label>
                <Input
                  id="usagePerUser"
                  type="number"
                  min="1"
                  placeholder="1"
                  disabled={isPending}
                  {...field("usagePerUser")}
                />
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={isPending}
            >
              Cancel
            </Button>
            <Button type="submit" disabled={isPending}>
              {isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {isEditing ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

input.content:
"use client";

import { Percent, Plus, Search, Tag } from "lucide-react";
import { useState } from "react";

import { CouponDialog } from "@/components/admin/coupon-dialog";
import { Pagination } from "@/components/admin/pagination";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useDeleteCoupon, useToggleCouponStatus, useCoupons } from "@/hooks/use-coupons";
import type { CouponDto } from "@/lib/api";

const PAGE_SIZE = 20;

function formatDiscount(coupon: CouponDto): string {
  if (coupon.discountType === "Percentage") {
    return `${coupon.discountValue}%`;
  }
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(coupon.discountValue);
}

function formatDate(iso: string | null | undefined): string {
  if (!iso) return "—";
  return new Date(iso).toLocaleDateString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

function CouponStatusBadge({ isActive }: { isActive: boolean }) {
  return (
    <Badge
      variant={isActive ? "default" : "secondary"}
      className={
        isActive
          ? "bg-success/15 text-success-foreground border-success/30"
          : ""
      }
    >
      {isActive ? "Active" : "Inactive"}
    </Badge>
  );
}

export default function CouponsPage() {
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [activeFilter, setActiveFilter] = useState<string>("all");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingCoupon, setEditingCoupon] = useState<CouponDto | null>(null);

  const isActiveParam =
    activeFilter === "active"
      ? true
      : activeFilter === "inactive"
        ? false
        : undefined;

  const { data, isLoading } = useCoupons({
    page,
    pageSize: PAGE_SIZE,
    isActive: isActiveParam,
    search: search || undefined,
  });

  const deleteCoupon = useDeleteCoupon();
  const toggleStatus = useToggleCouponStatus();

  function handleEdit(coupon: CouponDto) {
    setEditingCoupon(coupon);
    setDialogOpen(true);
  }

  function handleAddNew() {
    setEditingCoupon(null);
    setDialogOpen(true);
  }

  function handleDialogClose() {
    setDialogOpen(false);
    setEditingCoupon(null);
  }

  function handleToggleStatus(coupon: CouponDto) {
    toggleStatus.mutate({ id: coupon.id, isActive: !coupon.isActive });
  }

  function handleDelete(id: string) {
    if (!window.confirm("Delete this coupon? This action cannot be undone."))
      return;
    deleteCoupon.mutate(id);
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Coupons</h1>
          <p className="text-muted-foreground">
            Manage discount coupons and promo codes
          </p>
        </div>
        <Button onClick={handleAddNew}>
          <Plus className="mr-2 h-4 w-4" />
          Add Coupon
        </Button>
      </div>

      {/* Filters */}
      <div className="flex gap-3">
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search coupons..."
            value={search}
            onChange={(e) => {
              setSearch(e.target.value);
              setPage(1);
            }}
            className="pl-9"
          />
        </div>
        <Select
          value={activeFilter}
          onValueChange={(v) => {
            setActiveFilter(v);
            setPage(1);
          }}
        >
          <SelectTrigger className="w-36">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="active">Active</SelectItem>
            <SelectItem value="inactive">Inactive</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Table */}
      <div className="rounded-lg border bg-card">
        {isLoading ? (
          <div className="p-6 space-y-4">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="flex items-center space-x-4">
                <Skeleton className="h-10 w-24 rounded" />
                <div className="space-y-2 flex-1">
                  <Skeleton className="h-4 w-[200px]" />
                  <Skeleton className="h-4 w-[120px]" />
                </div>
                <Skeleton className="h-8 w-16 rounded" />
              </div>
            ))}
          </div>
        ) : data && data.items.length > 0 ? (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Code</TableHead>
                <TableHead>Discount</TableHead>
                <TableHead>Usage</TableHead>
                <TableHead>Valid Period</TableHead>
                <TableHead>Status</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.items.map((coupon) => (
                <TableRow key={coupon.id}>
                  <TableCell>
                    <div>
                      <div className="flex items-center gap-2">
                        {coupon.discountType === "Percentage" ? (
                          <Percent className="h-3.5 w-3.5 text-muted-foreground" />
                        ) : (
                          <Tag className="h-3.5 w-3.5 text-muted-foreground" />
                        )}
                        <span className="font-mono font-semibold text-sm">
                          {coupon.code}
                        </span>
                      </div>
                      <p className="text-xs text-muted-foreground mt-0.5 max-w-[200px] truncate">
                        {coupon.description}
                      </p>
                    </div>
                  </TableCell>
                  <TableCell>
                    <div className="font-medium">{formatDiscount(coupon)}</div>
                    {coupon.minOrderAmount && (
                      <div className="text-xs text-muted-foreground">
                        Min ${coupon.minOrderAmount}
                      </div>
                    )}
                  </TableCell>
                  <TableCell>
                    <span className="text-sm">
                      {coupon.timesUsed}
                      {coupon.usageLimit ? ` / ${coupon.usageLimit}` : ""}
                    </span>
                  </TableCell>
                  <TableCell>
                    <div className="text-sm">{formatDate(coupon.validFrom)}</div>
                    {coupon.validUntil && (
                      <div className="text-xs text-muted-foreground">
                        → {formatDate(coupon.validUntil)}
                      </div>
                    )}
                  </TableCell>
                  <TableCell>
                    <CouponStatusBadge isActive={coupon.isActive} />
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex items-center justify-end gap-2">
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleToggleStatus(coupon)}
                        disabled={toggleStatus.isPending}
                      >
                        {coupon.isActive ? "Deactivate" : "Activate"}
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleEdit(coupon)}
                      >
                        Edit
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        className="text-destructive hover:text-destructive"
                        onClick={() => handleDelete(coupon.id)}
                        disabled={deleteCoupon.isPending}
                      >
                        Delete
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        ) : (
          <div className="p-12 text-center">
            <div className="mb-4 text-muted-foreground">
              <Tag className="mx-auto h-12 w-12" />
            </div>
            <h3 className="text-lg font-medium text-foreground">
              No coupons found
            </h3>
            <p className="mt-1 text-muted-foreground">
              {search || activeFilter !== "all"
                ? "Try adjusting your filters"
                : "Get started by creating your first coupon"}
            </p>
            {!search && activeFilter === "all" && (
              <Button onClick={handleAddNew} className="mt-4">
                <Plus className="mr-2 h-4 w-4" />
                Add Coupon
              </Button>
            )}
          </div>
        )}
      </div>

      {/* Pagination */}
      {data && data.totalCount > 0 && (
        <Pagination
          page={data.page}
          pageSize={data.pageSize}
          totalCount={data.totalCount}
          onPageChange={setPage}
        />
      )}

      {/* Create/Edit Dialog */}
      <CouponDialog
        open={dialogOpen}
        onClose={handleDialogClose}
        coupon={editingCoupon}
      />
    </div>
  );
}

